#define BUCKET_WARP_LOG_SIZE	5
#define BUCKET_WARP_N			1

#ifdef BUCKET_WG_SIZE_1
#define BUCKET_THREAD_N BUCKET_WG_SIZE_1
#else
#define BUCKET_THREAD_N			(BUCKET_WARP_N << BUCKET_WARP_LOG_SIZE)
#endif
#define BUCKET_BLOCK_MEMORY		(DIVISIONS * BUCKET_WARP_N)
#define BUCKET_BAND				128

#define LOG_DIVISIONS 10
#define DIVISIONS (1 << LOG_DIVISIONS)

__global__ void
bucketcount( float *input, int *indice, unsigned int *d_prefixoffsets, int size, float *pivotPoints)
{
    volatile unsigned int s_offset[BUCKET_BLOCK_MEMORY]; 

    const unsigned int threadTag = threadIdx.x << (32 - BUCKET_WARP_LOG_SIZE);
    const int warpBase = (threadIdx.x >> BUCKET_WARP_LOG_SIZE) * DIVISIONS; 
    const int numThreads = blockDim.x * gridDim.x;

    // Initialize shared memory
    for (int i = threadIdx.x; i < BUCKET_BLOCK_MEMORY; i += blockDim.x)
        s_offset[i] = 0; 

    __syncthreads(); 

    for (int tid = blockIdx.x * blockDim.x + threadIdx.x; tid < size; tid += numThreads) {
        float elem = input[tid]; 

        // Binary search for bucket index
        int idx  = DIVISIONS/2 - 1; 
        int jump = DIVISIONS/4; 
        float piv = pivotPoints[idx]; 

        while(jump >= 1){
            if(piv > elem) {
                idx = idx - jump;
            } else {
                idx = idx + jump;
            }
            // Bounds check
            if(idx < 0) idx = 0;
            if(idx >= DIVISIONS) idx = DIVISIONS - 1;

            piv = pivotPoints[idx]; 
            jump = jump >> 1; 
        }

        if(piv <= elem) {
            idx = idx + 1;
        }

        if(idx >= DIVISIONS) idx = DIVISIONS - 1;
        if(idx < 0) idx = 0;

        // Atomic add with thread tag simulation
        unsigned int offset_idx = warpBase + idx;
        unsigned int count;
        unsigned int old_val;
        unsigned int new_val;

        do {
            old_val = s_offset[offset_idx];
            count = (old_val & 0x07FFFFFFU) + 1;
            new_val = threadTag | count;

            // Use atomic_cmpxchg to simulate the volatile write/read check
            unsigned int exchanged = atomic_cmpxchg(&s_offset[offset_idx], old_val, new_val);
            if(exchanged == old_val) {
                // Success
                break;
            }
            // Retry with new value
        } while(1);

        unsigned int final_count = (s_offset[offset_idx] & 0x07FFFFFFU) - 1;
        indice[tid] = (final_count << LOG_DIVISIONS) + idx;  
    }

    __syncthreads(); 

    int prefixBase = blockIdx.x * BUCKET_BLOCK_MEMORY; 

    for (int i = threadIdx.x; i < BUCKET_BLOCK_MEMORY; i += blockDim.x)
        d_prefixoffsets[prefixBase + i] = s_offset[i] & 0x07FFFFFFU; 
}

__global__ void bucketprefixoffset(unsigned int *d_prefixoffsets, unsigned int *d_offsets, int blocks) {
    int tid = blockIdx.x * blockDim.x + threadIdx.x; 
    int size = blocks * BUCKET_BLOCK_MEMORY; 
    int sum = 0; 

    // Accumulate sums for every DIVISIONS-th element starting from tid
    for (int i = tid; i < size; i += DIVISIONS) {
        unsigned int x = d_prefixoffsets[i]; 
        d_prefixoffsets[i] = sum; 
        sum += x; 
    }

    // Store the total sum for this thread's starting position if it corresponds to a valid output slot
    if(tid < DIVISIONS) {
        d_offsets[tid] = sum; 
    }
}

__global__ void
bucketsort(float *input, int *indice, float *output, int size, unsigned int *d_prefixoffsets, 
           unsigned int *l_offsets)
{
    volatile unsigned int s_offset[BUCKET_BLOCK_MEMORY]; 

    int prefixBase = blockIdx.x * BUCKET_BLOCK_MEMORY; 
    const int warpBase = (threadIdx.x >> BUCKET_WARP_LOG_SIZE) * DIVISIONS; 
    const int numThreads = blockDim.x * gridDim.x;

    // Initialize shared offsets
    for (int i = threadIdx.x; i < BUCKET_BLOCK_MEMORY; i += blockDim.x)
        s_offset[i] = l_offsets[i & (DIVISIONS - 1)] + d_prefixoffsets[prefixBase + i]; 

    __syncthreads(); 

    for (int tid = blockIdx.x * blockDim.x + threadIdx.x; tid < size; tid += numThreads) {
        float elem = input[tid]; 
        int id = indice[tid]; 

        int bucket_idx = id & (DIVISIONS - 1);
        int offset_idx = id >> LOG_DIVISIONS;

        int write_idx = s_offset[warpBase + bucket_idx] + offset_idx;

        if(write_idx < (size + DIVISIONS*4)) {
            output[write_idx] = elem;
        }
    }
}

