#define BLOCKSIZE	256
#define ROW_LENGTH	(BLOCKSIZE * 4)
#define ROWS		4096

#define LOG_DIVISIONS 10
#define DIVISIONS (1 << LOG_DIVISIONS)

static inline float4 sortElem(float4 r) {
    float4 nr;

    nr.x = (r.y < r.x) ? r.y : r.x; 
    nr.y = (r.x < r.y) ? r.y : r.x; 
    nr.z = (r.w < r.z) ? r.w : r.z; 
    nr.w = (r.z < r.w) ? r.w : r.z; 

    r.x = (nr.z < nr.x) ? nr.z : nr.x; 
    r.y = (nr.w < nr.y) ? nr.w : nr.y; 
    r.z = (nr.x < nr.z) ? nr.z : nr.x; 
    r.w = (nr.y < nr.w) ? nr.w : nr.y; 

    nr.x = r.x; 
    nr.y = (r.z < r.y) ? r.z : r.y; 
    nr.z = (r.y < r.z) ? r.z : r.y; 
    nr.w = r.w; 
    return nr; 
}

static inline float4 getLowest(float4 a, float4 b)
{
    a.x = (b.w > a.x) ? a.x : b.w; 
    a.y = (b.z > a.y) ? a.y : b.z; 
    a.z = (b.y > a.z) ? a.z : b.y; 
    a.w = (b.x > a.w) ? a.w : b.x; 
    return a; 
}

static inline float4 getHighest(float4 a, float4 b)
{
    b.x = (b.x <= a.w) ? a.w : b.x; 
    b.y = (b.y <= a.z) ? a.z : b.y; 
    b.z = (b.z <= a.y) ? a.y : b.z; 
    b.w = (b.w <= a.x) ? a.x : b.w; 
    return b; 
}

__global__ void
mergeSortFirst(float4 *result, int listsize, const float4 *texData) 
{
    int idx = blockIdx.x * blockDim.x + threadIdx.x;

    if(idx < listsize/4){
        float4 r = texData[idx];
        result[idx] = sortElem(r); 
    }
}

__global__ void
mergeSortPass(float4 *result, int nrElems, int threadsPerDiv, 
              const int *constStartAddr, const float4 *texData) 
{
    int tid = (blockIdx.x * blockDim.x) + threadIdx.x; 

    int division = tid / threadsPerDiv; 
    if(division >= DIVISIONS) return; 

    int int_tid = tid - division * threadsPerDiv; 
    int Astart = constStartAddr[division] + int_tid * nrElems; 

    int Bstart = Astart + nrElems/2;

    // Check bounds before accessing result
    if(constStartAddr[division + 1] <= Astart) 
        return; 

    int limit = constStartAddr[division + 1] - Astart;

    if(constStartAddr[division + 1] <= Bstart){
        for(int i=0; i < limit; i++)
        {
            result[Astart + i] = texData[Astart + i]; 
        }
        return; 
    }

    int aidx = 0; 
    int bidx = 0; 
    int outidx = 0; 
    float4 a, b;

    // Ensure indices are within valid range before fetching
    if(Astart + aidx >= constStartAddr[division+1]) return;
    if(Bstart + bidx >= constStartAddr[division+1]) {
        // Only A has elements
        for(int i=0; i < limit; i++) {
            result[Astart+i] = texData[Astart+i];
        }
        return;
    }

    a = texData[Astart + aidx];  
    b = texData[Bstart + bidx]; 

    int max_a = nrElems/2;
    int max_b = constStartAddr[division + 1] - Bstart;
    if(max_b > nrElems/2) max_b = nrElems/2;

    while(true)
    {
        float4 nextA, nextB;
        bool hasNextA = (aidx + 1 < max_a);
        bool hasNextB = (bidx + 1 < max_b);

        if(hasNextA) nextA = texData[Astart + aidx + 1];
        if(hasNextB) nextB = texData[Bstart + bidx + 1];

        float4 na = getLowest(a,b); 
        float4 nb = getHighest(a,b); 
        a = sortElem(na); 
        b = sortElem(nb); 

        result[Astart + outidx] = a; 
        outidx++;

        if(hasNextA){
            if(hasNextB){
                if(nextB.x > nextA.x) { aidx++; a = nextA; }  
                else { bidx++; a = nextB; }
            }
            else {
                aidx++; a = nextA;
            }
        }
        else {
            if(hasNextB){
                bidx++; a = nextB;
            }
            else {
                break; 
            }
        }
    }
    result[Astart + outidx] = b;
}

__global__ void
mergepack(float *orig, float *result, const int *finalStartAddr, const int *constStartAddr, const int *nullElems) 
{
    int idx = (blockIdx.x * blockDim.x) + threadIdx.x; 
    int division = blockIdx.y; 

    int start = finalStartAddr[division];
    int end = finalStartAddr[division + 1];

    if(start + idx >= end) return; 

    int src_idx = constStartAddr[division]*4 + nullElems[division] + idx;
    result[start + idx] = orig[src_idx]; 
}
